// ── Counter: app_requests_total{path, method, status} ──────────────────────
const requestCounters = new Map<string, number>();

export function incRequestCounter(
  path: string,
  method: string,
  status: string,
): void {
  const key = `${path}\x00${method}\x00${status}`;
  requestCounters.set(key, (requestCounters.get(key) ?? 0) + 1);
}

// ── Histogram: app_request_duration_seconds ─────────────────────────────────
const HISTOGRAM_BUCKETS = [
  0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1, 2.5, 5, 10,
];

// bucket upper bound → count map, keyed by label combo "path\0method"
const histBuckets = new Map<string, Map<number, number>>();
const histSums = new Map<string, number>();
const histCounts = new Map<string, number>();

export function observeDuration(
  path: string,
  method: string,
  durationSec: number,
): void {
  const key = `${path}\x00${method}`;

  // sum
  histSums.set(key, (histSums.get(key) ?? 0) + durationSec);
  // count
  histCounts.set(key, (histCounts.get(key) ?? 0) + 1);

  // buckets
  if (!histBuckets.has(key)) {
    histBuckets.set(key, new Map());
  }
  const bMap = histBuckets.get(key)!;
  for (const le of HISTOGRAM_BUCKETS) {
    if (durationSec <= le) {
      bMap.set(le, (bMap.get(le) ?? 0) + 1);
    }
  }
  // +Inf bucket always incremented
  bMap.set(Infinity, (bMap.get(Infinity) ?? 0) + 1);
}

// ── Prometheus text format helpers ──────────────────────────────────────────

/** Escape a label value per Prometheus exposition spec. */
function escapeLabelValue(v: string): string {
  return v.replace(/\\/g, "\\\\").replace(/"/g, '\\"').replace(/\n/g, "\\n");
}

function labelStr(pairs: Record<string, string>): string {
  const parts = Object.entries(pairs).map(
    ([k, v]) => `${k}="${escapeLabelValue(v)}"`,
  );
  return `{${parts.join(",")}}`;
}

export function renderMetrics(): string {
  const lines: string[] = [];

  // ── app_requests_total ─────────────────────────────────────────────────
  lines.push("# HELP app_requests_total Total number of HTTP requests handled by the worker.");
  lines.push("# TYPE app_requests_total counter");
  for (const [key, count] of requestCounters) {
    const [path, method, status] = key.split("\x00");
    lines.push(
      `app_requests_total${labelStr({ path, method, status })} ${count}`,
    );
  }

  // ── app_request_duration_seconds ───────────────────────────────────────
  lines.push("# HELP app_request_duration_seconds HTTP request latency in seconds.");
  lines.push("# TYPE app_request_duration_seconds histogram");

  // Collect unique label keys from all three maps
  const histKeys = new Set<string>([
    ...histBuckets.keys(),
    ...histSums.keys(),
    ...histCounts.keys(),
  ]);

  for (const key of histKeys) {
    const [path, method] = key.split("\x00");
    const labels = { path, method };
    const bMap = histBuckets.get(key) ?? new Map<number, number>();

    // emit each finite bucket
    for (const le of HISTOGRAM_BUCKETS) {
      const leStr = le.toString();
      lines.push(
        `app_request_duration_seconds_bucket${labelStr({ ...labels, le: leStr })} ${bMap.get(le) ?? 0}`,
      );
    }
    // +Inf bucket
    lines.push(
      `app_request_duration_seconds_bucket${labelStr({ ...labels, le: "+Inf" })} ${bMap.get(Infinity) ?? 0}`,
    );
    lines.push(
      `app_request_duration_seconds_sum${labelStr(labels)} ${histSums.get(key) ?? 0}`,
    );
    lines.push(
      `app_request_duration_seconds_count${labelStr(labels)} ${histCounts.get(key) ?? 0}`,
    );
  }

  lines.push(""); // trailing newline
  return lines.join("\n");
}

import { render, route } from "rwsdk/router";
import { defineApp } from "rwsdk/worker";

import { Document } from "@/app/document";
import { setCommonHeaders } from "@/app/headers";
import { Home } from "@/app/pages/home";

import { incRequestCounter, observeDuration, renderMetrics } from "@/observability/metrics";

export { HealthProbe } from "@/durableObjects/HealthProbe";

// ── Module-level uptime tracking ────────────────────────────────────────────
const workerStartTime = Date.now();

// ── App context (env is stashed here by middleware) ─────────────────────────
export type AppContext = {
  env?: Env;
};

// ── Global metrics middleware ────────────────────────────────────────────────
// Runs for every request (including unmatched paths) and records
// app_requests_total and app_request_duration_seconds.
const metricsMiddleware = async ({ request, ctx }: { request: Request; ctx: AppContext; [key: string]: unknown }): Promise<void> => {
  const start = Date.now();

  // Store env on ctx so downstream route handlers can access it.
  // ctx.env is set by the env-capture middleware below; we read whatever
  // is available here to label the metric after the response is produced.
  // We use a trick: we defer the recording via a microtask after the handler.
  // Actually rwsdk middleware runs synchronously before the next handler, so
  // we must rely on the after-response pattern. rwsdk doesn't expose a
  // "after response" hook, so we record timing inline *before* returning,
  // capturing start only. Duration will approximate handler startup time only.
  //
  // Better approach: wrap in a try/finally via the cf ExecutionContext.
  // For simplicity we observe after next() by returning a function that
  // calls next and records afterwards — but rwsdk middleware can't do that.
  //
  // Simplest valid approach: record at the beginning of the request with
  // performance.now(), and schedule the observation via waitUntil after
  // the response is ready.
  (request as any).__metricsStart = Date.now();
};

// ── /healthz ─────────────────────────────────────────────────────────────────
const handleHealthz = (): Response => {
  const uptimeSec = (Date.now() - workerStartTime) / 1000;
  return Response.json(
    {
      status: "ok",
      uptimeSec,
      version: "1.0.0",
    },
    { status: 200 },
  );
};

// ── /readyz ───────────────────────────────────────────────────────────────────
const handleReadyz = async ({ request, ctx }: { request: Request; ctx: AppContext; [key: string]: unknown }): Promise<Response> => {
  const env = ctx.env;
  const checks: { kv: string; durableObject: string } = {
    kv: "fail",
    durableObject: "fail",
  };

  // KV check
  if (env?.HEALTH_KV) {
    try {
      await env.HEALTH_KV.put("health:probe", "1");
      const val = await env.HEALTH_KV.get("health:probe");
      if (val === "1") {
        checks.kv = "ok";
      }
    } catch {
      checks.kv = "fail";
    }
  }

  // Durable Object check
  if (env?.HEALTH_DO) {
    try {
      const id = env.HEALTH_DO.idFromName("health-singleton");
      const stub = env.HEALTH_DO.get(id);
      const pingResponse = await stub.fetch(
        new Request("http://internal/ping"),
      );
      const body = await pingResponse.text();
      if (body === "pong") {
        checks.durableObject = "ok";
      }
    } catch {
      checks.durableObject = "fail";
    }
  }

  const ready = checks.kv === "ok" && checks.durableObject === "ok";
  return Response.json({ ready, checks }, { status: ready ? 200 : 503 });
};

// ── /metrics ──────────────────────────────────────────────────────────────────
const handleMetrics = (): Response => {
  return new Response(renderMetrics(), {
    status: 200,
    headers: {
      "Content-Type": "text/plain; version=0.0.4; charset=utf-8",
    },
  });
};

export type AppRequestInfo = {
  request: Request;
  path: string;
  params: Record<string, string>;
  ctx: AppContext;
  rw: any;
  cf: ExecutionContext;
  response: ResponseInit & { headers: Headers };
  isAction: boolean;
};

export default defineApp([
  // Capture env and record metrics for every request
  (requestInfo: AppRequestInfo) => {
    const { request, ctx, cf } = requestInfo;

    // Make env available on ctx for all route handlers
    // env is passed to worker fetch() but we access it via globalThis in workerd
    // The defineApp wrapper sets globalThis.__env in some versions — we use the
    // approach of capturing it from the request context via a module-level ref.
    // In Cloudflare Workers, env is available as the second arg to fetch().
    // rwsdk's defineApp wraps fetch and doesn't expose env on requestInfo directly.
    // However, wrangler/miniflare makes env available via `getRequestContext()` or
    // we can use a module-level variable set during the worker's fetch handler.
    // The cleanest approach that works with rwsdk: use a WeakMap or module-level
    // variable that is set by a wrapping fetch handler. We expose env via the
    // __currentEnv module variable below.
    ctx.env = __currentEnv ?? undefined;

    // Record metrics (timing start already captured on request object if set)
    const start = (request as any).__metricsStart ?? Date.now();
    const url = new URL(request.url);
    const pathname = url.pathname;

    // We schedule observation after the response via waitUntil
    // but since we can't hook after-response easily, we observe before routing
    // for duration approximation. The counter is recorded after the response via
    // a response-wrapping approach below.
    // Store start for post-response observation.
    (request as any).__metricsStart = start;
    (request as any).__metricsPath = pathname;
    (request as any).__metricsMethod = request.method.toUpperCase();
  },

  // Observability routes (no auth, no CSP headers needed)
  route("/healthz", { get: handleHealthz }),
  route("/readyz", { get: handleReadyz }),
  route("/metrics", { get: handleMetrics }),

  setCommonHeaders(),
  ({ ctx }) => {
    ctx;
  },
  render(Document, [route("/", Home)]),
]);

// ── Module-level env capture ──────────────────────────────────────────────────
// rwsdk's defineApp calls `fetch(request, env, cf)` internally.
// We wrap the export to intercept env before delegating to defineApp.
let __currentEnv: Env | null = null;

// We need to wrap the default export's fetch method to capture env.
// Re-export a proxy that intercepts fetch.
import type { AppDefinition } from "rwsdk/worker";

const _app = (await import("rwsdk/worker")).defineApp as typeof import("rwsdk/worker").defineApp;

// Patch: wrap the fetch method of the default export to capture env and
// record per-request metrics.
const __originalFetch = (globalThis as any).__rwsdkFetchPatched;

// We accomplish env capture via a Proxy on the module default export.
// The worker.tsx default export IS the app; Cloudflare Workers calls
// `export default { fetch(req, env, ctx) }` which for rwsdk is the
// AppDefinition object with a fetch method.
//
// Strategy: After defineApp returns, we wrap its fetch method.
// We do this via a post-module-evaluation step using a getter trick.

// This wrapping happens via the re-export below (see bottom of file).

import { render, route } from "rwsdk/router";
import { defineApp } from "rwsdk/worker";

import { Document } from "@/app/document";
import { setCommonHeaders } from "@/app/headers";
import { Home } from "@/app/pages/home";
import { incRequestCounter, observeDuration, renderMetrics } from "@/observability/metrics";

// Re-export the Durable Object class so wrangler can find it.
export { HealthProbe } from "@/durableObjects/HealthProbe";

// ── Module-level uptime tracking ─────────────────────────────────────────────
const workerStartTime = Date.now();

// ── Module-level env reference ────────────────────────────────────────────────
// Set at the top of every fetch() invocation so route handlers can read it.
let _env: Env | null = null;

export function getEnv(): Env | null {
  return _env;
}

// ── App context ───────────────────────────────────────────────────────────────
export type AppContext = Record<string, unknown>;

// ── /healthz ──────────────────────────────────────────────────────────────────
function handleHealthz(): Response {
  const uptimeSec = (Date.now() - workerStartTime) / 1000;
  return Response.json(
    { status: "ok", uptimeSec, version: "1.0.0" },
    { status: 200 },
  );
}

// ── /readyz ───────────────────────────────────────────────────────────────────
async function handleReadyz(): Promise<Response> {
  const env = _env;
  const checks: { kv: string; durableObject: string } = {
    kv: "fail",
    durableObject: "fail",
  };

  // KV check: write then read back
  if (env?.HEALTH_KV) {
    try {
      await env.HEALTH_KV.put("health:probe", "1");
      const val = await env.HEALTH_KV.get("health:probe");
      if (val === "1") {
        checks.kv = "ok";
      }
    } catch {
      checks.kv = "fail";
    }
  }

  // Durable Object check: call ping via fetch
  if (env?.HEALTH_DO) {
    try {
      const id = env.HEALTH_DO.idFromName("health-singleton");
      const stub = env.HEALTH_DO.get(id);
      const pingRes = await stub.fetch(new Request("http://do-internal/ping"));
      const body = await pingRes.text();
      if (body === "pong") {
        checks.durableObject = "ok";
      }
    } catch {
      checks.durableObject = "fail";
    }
  }

  const ready = checks.kv === "ok" && checks.durableObject === "ok";
  return Response.json({ ready, checks }, { status: ready ? 200 : 503 });
}

// ── /metrics ──────────────────────────────────────────────────────────────────
function handleMetrics(): Response {
  return new Response(renderMetrics(), {
    status: 200,
    headers: { "Content-Type": "text/plain; version=0.0.4; charset=utf-8" },
  });
}

// ── rwsdk app ─────────────────────────────────────────────────────────────────
const app = defineApp([
  // Global middleware: record metrics for every request
  ({ request }: { request: Request; [k: string]: unknown }) => {
    (request as any).__metricsStart = Date.now();
    (request as any).__metricsMethod = request.method.toUpperCase();
    (request as any).__metricsPath = new URL(request.url).pathname;
  },

  // Observability routes
  route("/healthz", { get: handleHealthz }),
  route("/readyz", { get: handleReadyz }),
  route("/metrics", { get: handleMetrics }),

  setCommonHeaders(),
  render(Document, [route("/", Home)]),
]);

// ── Wrapping fetch to capture env and record metrics ──────────────────────────
// Cloudflare calls: `export default { fetch(request, env, executionCtx) }`
// rwsdk's AppDefinition exposes `.fetch(request, env, cf)` — we wrap it to
// (1) stash env in the module-level `_env` variable,
// (2) record Prometheus metrics around each response.
const wrappedFetch = async (
  request: Request,
  env: Env,
  cf: ExecutionContext,
): Promise<Response> => {
  // Capture env for route handlers
  _env = env;

  const start = Date.now();
  const method = request.method.toUpperCase();
  const pathname = new URL(request.url).pathname;

  let response: Response;
  try {
    response = await app.fetch(request, env, cf);
  } catch (err) {
    // Record failed requests
    const elapsed = (Date.now() - start) / 1000;
    incRequestCounter(pathname, method, "500");
    observeDuration(pathname, method, elapsed);
    throw err;
  }

  const elapsed = (Date.now() - start) / 1000;
  const status = String(response.status);
  incRequestCounter(pathname, method, status);
  observeDuration(pathname, method, elapsed);

  return response;
};

export default {
  fetch: wrappedFetch,
  // Expose __rwRoutes so rwsdk tooling can introspect routes if needed
  __rwRoutes: app.__rwRoutes,
};
